import{_ as t,o as a,c as s,a4 as n}from"./chunks/framework.BIesbIg_.js";const u=JSON.parse('{"title":"Using GCF with LLMs","description":"","frontmatter":{},"headers":[],"relativePath":"guide/llm-integration.md","filePath":"guide/llm-integration.md"}'),o={name:"guide/llm-integration.md"};function i(r,e,d,l,c,h){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="using-gcf-with-llms" tabindex="-1">Using GCF with LLMs <a class="header-anchor" href="#using-gcf-with-llms" aria-label="Permalink to &quot;Using GCF with LLMs&quot;">​</a></h1><p>GCF is designed to be consumed by LLMs without special instructions. The format is self-documenting: section headers name the groups, positional fields are consistent, and the structure is flat enough that models parse it through pattern recognition.</p><h2 id="no-primer-needed" tabindex="-1">No primer needed <a class="header-anchor" href="#no-primer-needed" aria-label="Permalink to &quot;No primer needed&quot;">​</a></h2><p>Unlike formats that require explanation (YAML&#39;s indentation rules, XML&#39;s tag semantics), GCF payloads are immediately comprehensible to frontier models. In testing at 500 symbols, models achieved 100% accuracy on structured extraction questions without any format description in the prompt.</p><p>If you want to include a primer for clarity:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF format: Symbols are @id kind qualified_name score provenance. </span></span>
<span class="line"><span>Edges are @target&lt;@source type. Sections marked with ##.</span></span></code></pre></div><p>That&#39;s sufficient. Don&#39;t over-explain.</p><h2 id="prompt-patterns" tabindex="-1">Prompt patterns <a class="header-anchor" href="#prompt-patterns" aria-label="Permalink to &quot;Prompt patterns&quot;">​</a></h2><h3 id="what-symbols-are-relevant-to-this-task" tabindex="-1">&quot;What symbols are relevant to this task?&quot; <a class="header-anchor" href="#what-symbols-are-relevant-to-this-task" aria-label="Permalink to &quot;&quot;What symbols are relevant to this task?&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Here is the code context:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{gcf_payload}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Based on this context, implement the feature described below.</span></span></code></pre></div><p>The LLM reads the GCF payload naturally. It can identify top-scored symbols, trace call paths through edges, and understand the code topology from the hierarchical grouping.</p><h3 id="what-changed-since-last-time" tabindex="-1">&quot;What changed since last time?&quot; <a class="header-anchor" href="#what-changed-since-last-time" aria-label="Permalink to &quot;&quot;What changed since last time?&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The context has been updated. Here&#39;s what changed:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{gcf_delta_payload}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The symbols in ## removed are no longer relevant. </span></span>
<span class="line"><span>The symbols in ## added are new context. Adjust your approach.</span></span></code></pre></div><h3 id="session-continuity" tabindex="-1">Session continuity <a class="header-anchor" href="#session-continuity" aria-label="Permalink to &quot;Session continuity&quot;">​</a></h3><p>When using session deduplication, the LLM sees bare references (<code>@7 # previously transmitted</code>) alongside full declarations. It doesn&#39;t need to act on the bare refs; they&#39;re context markers that confirm overlap with prior responses.</p><h2 id="what-llms-extract-from-gcf" tabindex="-1">What LLMs extract from GCF <a class="header-anchor" href="#what-llms-extract-from-gcf" aria-label="Permalink to &quot;What LLMs extract from GCF&quot;">​</a></h2><p>Based on the comprehension eval (6 question types at 500 symbols):</p><table tabindex="0"><thead><tr><th>Question type</th><th>What the LLM extracts</th><th>Accuracy</th></tr></thead><tbody><tr><td>Symbol count</td><td>How many symbols total</td><td>100%</td></tr><tr><td>Edge count</td><td>How many edges total</td><td>100%</td></tr><tr><td>Top symbol</td><td>Highest-scored symbol name</td><td>100%</td></tr><tr><td>Top kind</td><td>Kind of the top symbol</td><td>100%</td></tr><tr><td>Target count</td><td>Symbols at distance 0</td><td>100%</td></tr><tr><td>Edge types</td><td>All unique edge types</td><td>100%</td></tr></tbody></table><p>JSON scored 66.7% on the same questions because field-name noise at 500 records overwhelms the model&#39;s counting circuits.</p><h2 id="token-budget-management" tabindex="-1">Token budget management <a class="header-anchor" href="#token-budget-management" aria-label="Permalink to &quot;Token budget management&quot;">​</a></h2><p>GCF payloads include <code>budget</code> and <code>tokens</code> in the header. Use these for client-side budget tracking:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=10</span></span></code></pre></div><p>The producing tool can pack symbols up to the budget, and the consumer can verify how much budget was consumed. This enables multi-tool orchestration where each tool gets a share of the total context budget.</p><h2 id="structured-extraction-from-gcf" tabindex="-1">Structured extraction from GCF <a class="header-anchor" href="#structured-extraction-from-gcf" aria-label="Permalink to &quot;Structured extraction from GCF&quot;">​</a></h2><p>If you need the LLM to extract structured data FROM a GCF payload (e.g., &quot;list all function names&quot;), the format&#39;s regularity makes this reliable:</p><ul><li>Every symbol starts with <code>@{id}</code> (easy to regex)</li><li>Kind is always the second field (filter by type)</li><li>Score is always the fourth field (sort by relevance)</li><li>The <code>## targets</code> section is always the most relevant subset</li></ul><h2 id="error-handling" tabindex="-1">Error handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error handling&quot;">​</a></h2><p>If the LLM receives malformed GCF (truncated response, encoding error):</p><ul><li>The <code>symbols=N</code> header field lets it verify completeness</li><li>Group headers are self-describing (missing <code>## edges</code> means no edges)</li><li>Each line is independent (a corrupt line doesn&#39;t break parsing of subsequent lines)</li></ul>`,29)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
